// Solution
function is_valid_cherry_pick_hash(commit_hash) {
  if (commit_hash.length < 40) {
    return false;
  }
  let valid = true;
  for (let i = 0; i < commit_hash.length; i++) {
    let charCode = commit_hash.charCodeAt(i);
    if (!(charCode >= 48 && charCode <= 57) && !(charCode >= 65 && charCode <= 90) && !(charCode >= 97 && charCode <= 122)) {
      valid = false;
      break;
    }
  }
  return valid;
}

