class Solution:
    def is_valid_cherry_pick_hash(self, commit_hash: str) -> bool:
        if len(commit_hash) < 40:
            return False
        valid = True
        for char in commit_hash:
            charCode = ord(char)
            if (charCode < 48 or charCode > 57) and (charCode < 65 or charCode > 90) and (charCode < 97 or charCode > 122):
                valid = False
                break
        return valid
